import { LSPClient } from "./client.ts";
import type { LSPServerConfig } from "../types.ts";
import { getServerForFile, getServerForLanguage } from "../servers/registry.ts";

export class LSPClientPool {
	private clients = new Map<string, LSPClient>();
	private idleTimers = new Map<string, ReturnType<typeof setTimeout>>();
	private idleTimeoutMs: number;
	private customServers: LSPServerConfig[];
	private cwd: string;

	constructor(cwd: string, idleTimeoutMs = 300_000, customServers: LSPServerConfig[] = []) {
		this.cwd = cwd;
		this.idleTimeoutMs = idleTimeoutMs;
		this.customServers = customServers;
	}

	private poolKey(language: string): string {
		return `${language}:${this.cwd}`;
	}

	async getOrCreate(language: string): Promise<LSPClient> {
		const key = this.poolKey(language);
		const existing = this.clients.get(key);
		if (existing) {
			this.resetIdleTimer(key, existing);
			return existing;
		}

		const server = getServerForLanguage(language) ?? this.customServers.find((s) => s.language === language);
		if (!server) {
			throw new Error(`No LSP server configured for language: ${language}`);
		}

		const client = new LSPClient(language, this.cwd);
		await client.start(server.command);
		this.clients.set(key, client);
		this.resetIdleTimer(key, client);
		return client;
	}

	async getClientForFile(filePath: string): Promise<LSPClient | undefined> {
		const server = getServerForFile(filePath, this.customServers);
		if (!server) return undefined;
		return this.getOrCreate(server.language);
	}

	getClientForFileSync(filePath: string): LSPClient | undefined {
		const server = getServerForFile(filePath, this.customServers);
		if (!server) return undefined;
		const key = this.poolKey(server.language);
		return this.clients.get(key);
	}

	async shutdownAll(): Promise<void> {
		for (const [key, timer] of this.idleTimers) {
			clearTimeout(timer);
			this.idleTimers.delete(key);
		}
		const promises: Promise<void>[] = [];
		for (const [key, client] of this.clients) {
			promises.push(client.shutdown());
			this.clients.delete(key);
		}
		await Promise.all(promises);
	}

	async shutdownIdle(): Promise<number> {
		const now = Date.now();
		let count = 0;
		for (const [key, client] of this.clients) {
			if (now - client.lastActivity >= this.idleTimeoutMs) {
				clearTimeout(this.idleTimers.get(key));
				this.idleTimers.delete(key);
				await client.shutdown();
				this.clients.delete(key);
				count++;
			}
		}
		return count;
	}

	get size(): number {
		return this.clients.size;
	}

	private resetIdleTimer(key: string, client: LSPClient): void {
		const existing = this.idleTimers.get(key);
		if (existing) clearTimeout(existing);
		const timer = setTimeout(() => {
			const now = Date.now();
			if (now - client.lastActivity >= this.idleTimeoutMs) {
				client.shutdown().catch(() => {});
				this.clients.delete(key);
			}
			this.idleTimers.delete(key);
		}, this.idleTimeoutMs);
		timer.unref();
		this.idleTimers.set(key, timer);
	}
}

import { Connection, type ConnectionEvents } from "./connection.ts";
import { Lifecycle } from "./lifecycle.ts";
import { LSPClientState, type LSPClientStateValue, type Diagnostic } from "../types.ts";

export class LSPClient {
	private conn: Connection;
	private lifecycle: Lifecycle;
	private diagnosticsMap = new Map<string, Diagnostic[]>();
	private state: LSPClientStateValue = LSPClientState.Stopped;
	private lastActivityAt = Date.now();
	private language: string;
	private cwd: string;

	constructor(language: string, cwd: string) {
		this.language = language;
		this.cwd = cwd;
		const events: ConnectionEvents = {
			onResponse: () => {},
			onNotification: (method, params) => this.handleNotification(method, params),
			onError: () => {},
			onClose: () => {
				this.state = LSPClientState.Stopped;
			},
		};
		this.conn = new Connection(events);
		const rootUri = pathToUri(cwd);
		this.lifecycle = new Lifecycle(this.conn, rootUri);
	}

	get clientState(): LSPClientStateValue {
		return this.state;
	}

	get lastActivity(): number {
		return this.lastActivityAt;
	}

	getDiagnostics(fileUri: string): Diagnostic[] {
		return this.diagnosticsMap.get(fileUri) ?? [];
	}

	getAllDiagnostics(): Map<string, Diagnostic[]> {
		return new Map(this.diagnosticsMap);
	}

	async start(command: string[]): Promise<void> {
		if (this.state !== LSPClientState.Stopped) return;
		this.conn.start(command, this.cwd);
		await this.lifecycle.initialize();
		this.state = LSPClientState.Ready;
		this.lastActivityAt = Date.now();
	}

	async shutdown(): Promise<void> {
		if (this.state !== LSPClientState.Ready) {
			this.conn.kill();
			return;
		}
		await this.lifecycle.shutdown();
		this.conn.kill();
		this.state = LSPClientState.Stopped;
	}

	async sendRequest(method: string, params?: unknown): Promise<unknown> {
		if (this.state !== LSPClientState.Ready) {
			throw new Error(`Client not ready (state=${this.state})`);
		}
		this.lastActivityAt = Date.now();
		return this.conn.sendRequest(method, params);
	}

	sendNotification(method: string, params?: unknown): void {
		if (this.state !== LSPClientState.Ready) return;
		this.lastActivityAt = Date.now();
		this.conn.sendNotification(method, params);
	}

	private handleNotification(method: string, params: unknown): void {
		if (method === "textDocument/publishDiagnostics") {
			const p = params as { uri?: string; diagnostics?: Diagnostic[] };
			if (typeof p.uri === "string") {
				this.diagnosticsMap.set(p.uri, p.diagnostics ?? []);
			}
		}
	}
}

export function pathToUri(filePath: string): string {
	const absolute = filePath.startsWith("/") ? filePath : filePath;
	return `file://${absolute}`;
}

export function uriToPath(uri: string): string {
	return uri.replace(/^file:\/\//, "");
}

import { ChildProcess, spawn } from "node:child_process";
import type { JsonRpcRequest, JsonRpcNotification, JsonRpcResponse } from "../types.ts";

export interface ConnectionEvents {
	onResponse: (msg: JsonRpcResponse) => void;
	onNotification: (method: string, params: unknown) => void;
	onError: (error: Error) => void;
	onClose: () => void;
}

export class Connection {
	private proc: ChildProcess | null = null;
	private buffer = "";
	private nextId = 1;
	private pending = new Map<number | string, { resolve: (value: unknown) => void; reject: (error: Error) => void }>();
	private handlers: ConnectionEvents;
	private closed = false;

	constructor(handlers: ConnectionEvents) {
		this.handlers = handlers;
	}

	get isClosed(): boolean {
		return this.closed;
	}

	start(command: string[], cwd: string): void {
		this.proc = spawn(command[0], command.slice(1), {
			cwd,
			stdio: ["pipe", "pipe", "pipe"],
		});

		this.proc.stdout?.on("data", (chunk: Buffer) => {
			this.buffer += chunk.toString("utf-8");
			this.parseMessages();
		});

		this.proc.stderr?.on("data", (chunk: Buffer) => {
			// LSP servers log to stderr; ignore or forward
			void chunk;
		});

		this.proc.on("error", (err) => {
			this.handlers.onError(err);
		});

		this.proc.on("close", () => {
			this.closed = true;
			for (const [id, pending] of this.pending) {
				pending.reject(new Error(`Connection closed (pending request ${id})`));
			}
			this.pending.clear();
			this.handlers.onClose();
		});
	}

	sendRequest(method: string, params?: unknown): Promise<unknown> {
		return new Promise((resolve, reject) => {
			if (this.closed || !this.proc?.stdin?.writable) {
				reject(new Error("Connection is closed"));
				return;
			}
			const id = this.nextId++;
			const msg: JsonRpcRequest = { jsonrpc: "2.0", id, method, params };
			this.pending.set(id, { resolve, reject });
			this.write(msg);
		});
	}

	sendNotification(method: string, params?: unknown): void {
		if (this.closed || !this.proc?.stdin?.writable) return;
		const msg: JsonRpcNotification = { jsonrpc: "2.0", method, params };
		this.write(msg);
	}

	private write(msg: JsonRpcRequest | JsonRpcNotification): void {
		const body = JSON.stringify(msg);
		const header = `Content-Length: ${Buffer.byteLength(body, "utf-8")}\r\n\r\n`;
		this.proc!.stdin!.write(header + body, "utf-8");
	}

	private parseMessages(): void {
		while (this.buffer.length > 0) {
			const headerEnd = this.buffer.indexOf("\r\n\r\n");
			if (headerEnd === -1) break;

			const header = this.buffer.substring(0, headerEnd);
			const match = header.match(/^Content-Length:\s*(\d+)/i);
			if (!match) {
				this.buffer = this.buffer.substring(headerEnd + 4);
				continue;
			}

			const contentLength = Number.parseInt(match[1], 10);
			const bodyStart = headerEnd + 4;
			const bodyEnd = bodyStart + contentLength;

			if (this.buffer.length < bodyEnd) break;

			const body = this.buffer.substring(bodyStart, bodyEnd);
			this.buffer = this.buffer.substring(bodyEnd);

			try {
				const msg = JSON.parse(body) as JsonRpcResponse;
				if ("id" in msg && ("result" in msg || "error" in msg)) {
					const pending = this.pending.get(msg.id);
					if (pending) {
						this.pending.delete(msg.id);
						if (msg.error) {
							pending.reject(new Error(`LSP error ${msg.error.code}: ${msg.error.message}`));
						} else {
							pending.resolve(msg.result);
						}
					}
					this.handlers.onResponse(msg);
				} else if ("method" in msg) {
					this.handlers.onNotification((msg as unknown as { method: string }).method, (msg as unknown as { params?: unknown }).params);
				}
			} catch {
				// Ignore malformed messages
			}
		}
	}

	kill(): void {
		this.closed = true;
		for (const [, pending] of this.pending) {
			pending.reject(new Error("Connection killed"));
		}
		this.pending.clear();
		this.proc?.kill();
		this.proc = null;
	}
}

