import * as fs from "node:fs";
import * as path from "node:path";
import type { LSPServerConfig } from "../types.ts";

export const DEFAULT_SERVERS: LSPServerConfig[] = [
	{
		language: "typescript",
		command: ["npx", "typescript-language-server", "--stdio"],
		extensions: [".ts", ".tsx", ".js", ".jsx"],
		detectionFiles: ["tsconfig.json", "package.json"],
		installHint: "npm install -g typescript-language-server typescript",
	},
	{
		language: "python",
		command: ["pylsp", "--stdio"],
		extensions: [".py"],
		detectionFiles: ["requirements.txt", "pyproject.toml", "setup.py"],
		installHint: "pip install python-lsp-server",
	},
	{
		language: "rust",
		command: ["rust-analyzer"],
		extensions: [".rs"],
		detectionFiles: ["Cargo.toml"],
		installHint: "rustup component add rust-analyzer",
	},
	{
		language: "go",
		command: ["gopls", "serve"],
		extensions: [".go"],
		detectionFiles: ["go.mod"],
		installHint: "go install golang.org/x/tools/gopls@latest",
	},
];

export function detectLanguages(cwd: string): string[] {
	const languages: string[] = [];
	for (const server of DEFAULT_SERVERS) {
		for (const detectionFile of server.detectionFiles) {
			if (fs.existsSync(path.join(cwd, detectionFile))) {
				if (!languages.includes(server.language)) {
					languages.push(server.language);
				}
				break;
			}
		}
	}
	return languages;
}

export function getServerForLanguage(language: string): LSPServerConfig | undefined {
	return DEFAULT_SERVERS.find((s) => s.language === language);
}

export function getLanguageForFile(filePath: string, customServers: LSPServerConfig[] = []): string | undefined {
	const ext = path.extname(filePath);
	const allServers = [...DEFAULT_SERVERS, ...customServers];
	for (const server of allServers) {
		if (server.extensions.includes(ext)) {
			return server.language;
		}
	}
	return undefined;
}

export function getServerForFile(filePath: string, customServers: LSPServerConfig[] = []): LSPServerConfig | undefined {
	const language = getLanguageForFile(filePath, customServers);
	if (!language) return undefined;
	return getServerForLanguage(language) ?? customServers.find((s) => s.language === language);
}

import type { LSPClient } from "../client/client.ts";
import type { Hover } from "../types.ts";

export interface HoverParams {
	file: string;
	line: number;
	column: number;
}

export interface HoverResult {
	contents: unknown;
	range?: { start: { line: number; character: number }; end: { line: number; character: number } };
}

export async function hover(client: LSPClient, params: HoverParams): Promise<HoverResult | null> {
	const result = await client.sendRequest("textDocument/hover", {
		textDocument: { uri: `file://${params.file}` },
		position: { line: params.line - 1, character: params.column - 1 },
	}) as Hover | null;

	if (!result) return null;
	return {
		contents: result.contents,
		range: result.range
			? {
					start: { line: result.range.start.line + 1, character: result.range.start.character + 1 },
					end: { line: result.range.end.line + 1, character: result.range.end.character + 1 },
				}
			: undefined,
	};
}
